import React, { useEffect } from "react";
import CustomInput from "../../components/CustomInput";
import { useLocation, useNavigate } from "react-router-dom";
import { toast } from "react-toastify";
import * as yup from "yup";
import { useFormik } from "formik";
import { useDispatch, useSelector } from "react-redux";
import { createReport, getReports, resetState, updateReport } from "../../features/Report/reportIssueSlice";

// Validation schema
const schema = yup.object().shape({
  title: yup.string().required("Title is Required"),
  description: yup.string().required("Description is Required"),
  issueType: yup.string().required("Issue Type is Required"),
  priority: yup.string().required("Priority is Required"),
});

const ReportIssue = () => {
  const dispatch = useDispatch();
  const location = useLocation();
  const getIssueId = location.pathname.split("/")[3]; 
  const navigate = useNavigate();

  const issueState = useSelector((state) => state.issue) || {};
  const { isSuccess, isError, isLoading, createdIssue, updatedIssue } = issueState;

  
  useEffect(() => {
    if (getIssueId) {
      dispatch(getReports(getIssueId));  
    } else {
      dispatch(resetState());  
    }
  }, [getIssueId, dispatch]);

  useEffect(() => {
    if (isSuccess && createdIssue) {
      toast.success("Issue Reported Successfully!");
      dispatch(resetState());
      
    }
    if (isSuccess && updatedIssue) {
      toast.success("Issue Updated Successfully!");
      dispatch(resetState());
      navigate("/admin/list-issues");
    }
    if (isError) {
      toast.error("Something Went Wrong!");
    }
  }, [isSuccess, isError, createdIssue, updatedIssue, navigate, dispatch]);

  // Initializing the formik form with either existing data (for update) or empty fields (for new report)
  const formik = useFormik({
    initialValues: {
      title: createdIssue?.title || "",
      description: createdIssue?.description || "",
      issueType: createdIssue?.issueType || "",
      priority: createdIssue?.priority || "",
    },
    validationSchema: schema,
    onSubmit: (values) => {
      const user = JSON.parse(localStorage.getItem("user"));

      if (!user || !user._id) {
        toast.error("User data missing. Please log in again.");
        return;
      }

      const reportData = {
        ...values,
        user: user._id,  // 👈 This is the fix! Backend requires this.
        createdById: user._id,
        email: user.email,
        role: user.role
      };

      console.log("Submitting Report:", reportData); // Debugging

      if (getIssueId) {
        const data = { id: getIssueId, issueData: reportData };
        dispatch(updateReport(data));
      } else {
        dispatch(createReport(reportData));
        formik.resetForm();
      }
    },
  });



  return (
    <div>
      <h3 className="mb-4 title">
        {getIssueId ? "Update" : "Report"} Issue
      </h3>
      <div>
        <form onSubmit={formik.handleSubmit} className="d-flex gap-3 flex-column">
          <CustomInput
            type="text"
            className="py-2 mb-1"
            label="Enter Issue Title"
            name="title"
            onChng={formik.handleChange}
            onBlr={formik.handleBlur}
            val={formik.values.title}
          />
          <div className="error">
            {formik.touched.title && formik.errors.title}
          </div>

          <textarea
            className="form-control py-2 mb-1"
            placeholder="Enter Issue Description"
            name="description"
            onChange={formik.handleChange}
            onBlur={formik.handleBlur}
            value={formik.values.description}
          />
          <div className="error">
            {formik.touched.description && formik.errors.description}
          </div>

          <select
            name="issueType"
            onChange={formik.handleChange}
            onBlur={formik.handleBlur}
            value={formik.values.issueType}
            className="form-control py-2 mb-1"
          >
            <option value="">Select Issue Type</option>
            <option value="bug">Bug</option>
            <option value="feature_request">Feature Request</option>
            <option value="enhancement">Enhancement</option>
            <option value="transaction_issue">Transaction Issue</option>
            <option value="product_approval">Product Approval</option>
            <option value="account_access">Account Access Issues</option>
            <option value="shipping_tracking">Shipping and Tracking Issue</option>
            <option value="return_refund">Return and Refund</option>
            <option value="promotions_discounts">Promotions and Discounts</option>
            <option value="technical_issue">Technical/Website Issue</option>
            <option value="other">Other</option>
          </select>
          <div className="error">
            {formik.touched.issueType && formik.errors.issueType}
          </div>

          <select
            name="priority"
            onChange={formik.handleChange}
            onBlur={formik.handleBlur}
            value={formik.values.priority}
            className="form-control py-2 mb-1"
          >
            <option value="">Select Priority</option>
            <option value="low">Low</option>
            <option value="medium">Medium</option>
            <option value="high">High</option>
            <option value="critical">Critical</option>
          </select>
          <div className="error">
            {formik.touched.priority && formik.errors.priority}
          </div>

          <button type="submit" className="btn btn-primary mt-4" disabled={isLoading}>
            {getIssueId ? "Update Issue" : "Submit Report"}
          </button>
        </form>
      </div>
    </div>
  );
};

export default ReportIssue;
